from pymongo import MongoClient

def connect_to_db():
    client = MongoClient('mongodb://username:password@your-cluster.mongodb.net/database_name')
    return client['database_name']

def execute_filter(db, filter_expression):
    collection = db['collection_name']
    result = collection.find({ "$where": filter_expression })
    return list(result)

if __name__ == "__main__":
    db = connect_to_db()
    user_provided_filter = input("Enter your JavaScript filter expression: ")
    results = execute_filter(db, user_provided_filter)
    print(results)